// appCSS — the Solo Agency design system layered on top of Pico (dark-only).
// Served at /ui/assets/app.css. Hand-written, no build chain, no external
// assets. Tokens: blue-black canvas, layered surfaces, ONE lime accent.
const appCSS = `
/* ====== tokens ====== */
:root, [data-theme=dark] {
  --bg:#0B0F14; --side:#090D12; --panel:#111721; --raise:#161E2A;
  --line:#232D3D; --line-soft:#1A2230;
  --tx:#E8EDF4; --tx2:#8A97A8; --tx3:#5C6B7E;
  --acc:#9FE870; --acc-ink:#0B1407; --acc-dim:rgba(159,232,112,.12);
  --warn:#FBBF24; --warn-dim:rgba(251,191,36,.12);
  --bad:#F87171; --bad-dim:rgba(248,113,113,.12);
  --info:#60A5FA; --info-dim:rgba(96,165,250,.12);
  --r-card:10px; --r-ctl:8px;
  --shadow:0 1px 2px rgba(3,6,10,.5),0 8px 24px -12px rgba(3,6,10,.6);
  --mono:ui-monospace,"SF Mono",SFMono-Regular,Menlo,Consolas,monospace;

  /* retune Pico to the system */
  --pico-background-color:var(--bg);
  --pico-color:var(--tx);
  --pico-muted-color:var(--tx2);
  --pico-muted-border-color:var(--line);
  --pico-card-background-color:var(--panel);
  --pico-card-box-shadow:none;
  --pico-primary:var(--acc);
  --pico-primary-background:var(--acc);
  --pico-primary-border:var(--acc);
  --pico-primary-inverse:var(--acc-ink);
  --pico-primary-hover:#B2F085;
  --pico-primary-hover-background:#B2F085;
  --pico-primary-focus:rgba(159,232,112,.35);
  --pico-primary-underline:rgba(159,232,112,.5);
  --pico-border-radius:var(--r-ctl);
  --pico-form-element-background-color:#0D1219;
  --pico-form-element-border-color:var(--line);
  --pico-form-element-active-border-color:var(--acc);
  --pico-form-element-focus-color:rgba(159,232,112,.3);
  --pico-font-family:ui-sans-serif,-apple-system,BlinkMacSystemFont,"SF Pro Text","Segoe UI Variable","Segoe UI",Roboto,Helvetica,Arial,sans-serif;
  --pico-font-size:93.75%;
  --pico-line-height:1.55;
}
html{background:var(--bg)}
body{background:
  radial-gradient(1100px 500px at 85% -10%, rgba(159,232,112,.05), transparent 60%),
  radial-gradient(900px 480px at -10% 0%, rgba(96,165,250,.05), transparent 55%),
  var(--bg);
  color:var(--tx); min-height:100dvh}
::selection{background:rgba(159,232,112,.25)}
*{scrollbar-width:thin;scrollbar-color:var(--line) transparent}
*::-webkit-scrollbar{height:8px;width:8px}
*::-webkit-scrollbar-thumb{background:var(--line);border-radius:99px}
*::-webkit-scrollbar-track{background:transparent}

/* ====== shell ====== */
.shell{display:flex;min-height:100dvh}
.side{width:230px;flex:none;background:var(--side);border-right:1px solid var(--line-soft);
  display:flex;flex-direction:column;padding:14px 10px;position:sticky;top:0;height:100dvh;overflow-y:auto}
.brand{display:flex;align-items:center;gap:9px;padding:6px 10px 14px;text-decoration:none;color:var(--tx);font-weight:650;letter-spacing:.01em}
.brand svg{width:22px;height:22px;color:var(--acc)}
.brand:hover{color:var(--tx)}
.snav{display:flex;flex-direction:column;gap:2px}
.snav .ngroup{font-size:.68rem;text-transform:uppercase;letter-spacing:.09em;color:var(--tx3);
  padding:14px 10px 5px;font-weight:600}
.snav a{display:flex;align-items:center;gap:9px;padding:7px 10px;border-radius:8px;
  color:var(--tx2);text-decoration:none;font-size:.86rem;font-weight:500;line-height:1;
  border-left:2px solid transparent;transition:background .15s,color .15s}
.snav a svg{width:16px;height:16px;flex:none;opacity:.85}
.snav a:hover{background:var(--panel);color:var(--tx)}
.snav a.on{background:var(--acc-dim);color:var(--acc);border-left-color:var(--acc)}
.snav a.on svg{opacity:1}
.nbadge{margin-left:auto;background:var(--acc);color:var(--acc-ink);font-size:.68rem;
  font-weight:700;border-radius:99px;padding:2px 7px;line-height:1.2}
.maincol{flex:1;min-width:0;display:flex;flex-direction:column}
.topbar{display:flex;align-items:center;gap:12px;padding:10px 26px;
  border-bottom:1px solid var(--line-soft);background:rgba(11,15,20,.75);backdrop-filter:blur(8px);
  position:sticky;top:0;z-index:20;min-height:46px}
.crumb{font-size:.82rem;color:var(--tx3)}
.crumb a{color:var(--tx2);text-decoration:none;font-weight:600}
.crumb a:hover{color:var(--acc)}
.crumb .sep{margin:0 7px;color:var(--tx3)}
.live{margin-left:auto;display:none;align-items:center;gap:6px;font-size:.72rem;color:var(--tx3)}
.live.on{display:inline-flex}
.live i{width:7px;height:7px;border-radius:99px;background:var(--acc);
  box-shadow:0 0 0 3px rgba(159,232,112,.15);animation:pulse 2.4s infinite}
@keyframes pulse{0%,100%{opacity:1}50%{opacity:.45}}
main.content{padding:22px 26px 56px;max-width:1240px;width:100%;margin:0 auto}

/* ====== type ====== */
h1{font-size:1.35rem;font-weight:650;letter-spacing:-.01em;margin:0 0 4px}
.sub{color:var(--tx2);font-size:.86rem;margin:0 0 20px}
h2{font-size:.98rem;font-weight:650;margin:26px 0 10px;letter-spacing:-.005em}
h3{font-weight:600}
.mut{color:var(--tx2)}
code,pre{font-family:var(--mono)}
code{background:var(--raise);border:1px solid var(--line-soft);border-radius:6px;padding:.1em .45em;font-size:.8em;color:var(--tx)}
a{color:var(--info)}
a:hover{color:#8FC2FF}

/* ====== cards & grids ====== */
.card{background:var(--panel);border:1px solid var(--line-soft);border-radius:var(--r-card);
  box-shadow:var(--shadow),inset 0 1px 0 rgba(255,255,255,.025);padding:14px 16px;margin:10px 0}
.grid-cards{display:grid;grid-template-columns:repeat(auto-fill,minmax(250px,1fr));gap:12px}
.grid-cards .card{margin:0}

/* stat tiles */
.stats{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:12px;margin:16px 0 6px}
.stat{background:var(--panel);border:1px solid var(--line-soft);border-radius:var(--r-card);
  padding:13px 16px;box-shadow:var(--shadow)}
.stat b{display:block;font-size:1.65rem;font-weight:650;letter-spacing:-.02em;
  font-variant-numeric:tabular-nums;line-height:1.15}
.stat span{font-size:.74rem;color:var(--tx2);font-weight:500}
.stat.hot b{color:var(--acc)}

/* feature catalog */
.feat{display:flex;flex-direction:column;gap:8px;min-height:96px}
.feat .fhead{display:flex;align-items:center;gap:9px}
.feat .fico{width:30px;height:30px;flex:none;border-radius:8px;background:var(--raise);
  border:1px solid var(--line-soft);display:flex;align-items:center;justify-content:center;color:var(--acc)}
.feat .fico svg{width:16px;height:16px}
.feat strong{font-size:.88rem;font-weight:600;letter-spacing:-.005em}
.feat p{margin:0;font-size:.8rem;color:var(--tx2);line-height:1.5}
.feat .fkind{margin-left:auto}

/* client cards on home */
.clientcard{display:flex;flex-direction:column;gap:8px}
.clientcard .cname{font-size:1rem;font-weight:650}
.clientcard .cname a{color:var(--tx);text-decoration:none}
.clientcard .cname a:hover{color:var(--acc)}
.clientcard .cpath{font-family:var(--mono);font-size:.7rem;color:var(--tx3);
  overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.clientcard .cnums{display:flex;gap:14px;font-size:.78rem;color:var(--tx2);font-variant-numeric:tabular-nums}
.clientcard .cnums b{color:var(--tx);font-weight:650}
.clientcard .clinks{display:flex;gap:10px;flex-wrap:wrap;font-size:.8rem}

/* ====== pills / badges / dots ====== */
.pill{display:inline-flex;align-items:center;gap:5px;border:1px solid var(--line);
  border-radius:999px;padding:2px 9px;font-size:.72rem;font-weight:550;color:var(--tx2);
  vertical-align:middle;line-height:1.4;background:transparent}
.band-high{color:var(--acc);border-color:rgba(159,232,112,.4);background:var(--acc-dim)}
.band-review_carefully{color:var(--warn);border-color:rgba(251,191,36,.4);background:var(--warn-dim)}
.pill.err{color:var(--bad);border-color:rgba(248,113,113,.4);background:var(--bad-dim)}
.pill.info{color:var(--info);border-color:rgba(96,165,250,.4);background:var(--info-dim)}
.dot{width:7px;height:7px;border-radius:99px;display:inline-block;background:var(--tx3)}
.dot.ok{background:var(--acc)}.dot.warn{background:var(--warn)}.dot.err{background:var(--bad)}

/* ====== buttons ====== */
button,[role=button]{width:auto;border-radius:var(--r-ctl);font-weight:600;font-size:.84rem;
  transition:transform .12s,filter .15s}
button:active,[role=button]:active{transform:translateY(1px)}
button.ok,[role=button].ok{background:var(--acc);border-color:var(--acc);color:var(--acc-ink)}
button.ok:hover,[role=button].ok:hover{filter:brightness(1.07)}
button:not(.ok):not([data-act=approve]){background:var(--raise);border-color:var(--line);color:var(--tx)}
button:not(.ok):hover{border-color:var(--tx3)}
button:disabled{opacity:.45}

/* ====== tables ====== */
.wrap{overflow-x:auto;border:1px solid var(--line-soft);border-radius:var(--r-card);background:var(--panel)}
.wrap table{margin:0;font-size:.83rem}
table{--pico-background-color:transparent}
thead th, table tr:first-child th{position:sticky;top:0;background:var(--raise);color:var(--tx2);
  font-size:.7rem;text-transform:uppercase;letter-spacing:.07em;font-weight:600;
  border-bottom:1px solid var(--line);padding:9px 12px;white-space:nowrap}
td{border-bottom:1px solid var(--line-soft);padding:9px 12px;vertical-align:top}
tbody tr:hover td, tr:hover td{background:rgba(255,255,255,.015)}
tr:last-child td{border-bottom:none}

/* ====== forms ====== */
input,select,textarea{margin-bottom:.6rem;font-size:.87rem}
textarea{min-height:150px;white-space:pre-wrap;font-family:var(--mono);font-size:.8rem;line-height:1.55}
select{width:auto}
label{font-size:.84rem;font-weight:550}
label .mut{font-weight:450}

/* ====== approvals ====== */
.toolbar{position:sticky;top:56px;z-index:15;display:flex;align-items:center;gap:14px;flex-wrap:wrap;
  background:rgba(17,23,33,.85);backdrop-filter:blur(10px);border:1px solid var(--line);
  border-radius:var(--r-card);padding:10px 14px;margin:12px 0;box-shadow:var(--shadow)}
.toolbar label{margin:0;display:flex;align-items:center;gap:7px;cursor:pointer;font-size:.85rem}
.toolbar button{margin:0}
.toolbar input[type=checkbox]{margin:0}
.draft{border-left:3px solid var(--line);transition:opacity .2s}
.draft[data-band=high]{border-left-color:var(--acc)}
.draft[data-band=review_carefully]{border-left-color:var(--warn)}
.draft.done{opacity:.42}
.draft .subj input{font-weight:600;font-size:.9rem;font-family:var(--pico-font-family)}
.acts{display:flex;gap:8px;margin-top:10px;flex-wrap:wrap;align-items:center}
.acts button{margin-bottom:0;padding:6px 14px;font-size:.82rem}
.pick, #checkall{accent-color:var(--acc)}

/* ====== misc ====== */
.empty{border:1px dashed var(--line);border-radius:var(--r-card);padding:26px 20px;
  text-align:center;color:var(--tx2);font-size:.86rem;margin:12px 0}
.empty b{color:var(--tx)}
hr{border-color:var(--line-soft)}

/* ====== responsive ====== */
@media (max-width:900px){
  .shell{flex-direction:column}
  .side{width:100%;height:auto;position:static;flex-direction:row;align-items:center;
    overflow-x:auto;padding:8px 10px;border-right:none;border-bottom:1px solid var(--line-soft)}
  .brand{padding:0 8px 0 0}
  .brand span{display:none}
  .snav{flex-direction:row;gap:2px}
  .snav .ngroup{display:none}
  .snav a{padding:7px 9px;border-left:none;border-bottom:2px solid transparent;white-space:nowrap}
  .snav a.on{border-left:none;border-bottom-color:var(--acc)}
  .topbar{padding:8px 14px}
  main.content{padding:16px 14px 40px}
}
@media (prefers-reduced-motion:reduce){
  .live i{animation:none}
  button,[role=button],.snav a,.draft{transition:none}
}

/* ====== gate-2 additions ====== */
.bar{height:5px;border-radius:99px;background:var(--raise);border:1px solid var(--line-soft);overflow:hidden;margin:8px 0 2px}
.bar i{display:block;height:100%;background:var(--acc);border-radius:99px;transition:width .3s}
.bar.full i{background:var(--warn)}
.chips{display:flex;gap:7px;flex-wrap:wrap;align-items:center}
.steps{margin:10px 0 4px;padding-left:0;counter-reset:st;list-style:none}
.steps li{position:relative;padding:0 0 16px 40px;counter-increment:st}
.steps li::before{content:counter(st);position:absolute;left:0;top:-2px;width:26px;height:26px;
  border-radius:99px;background:var(--raise);border:1px solid var(--line);color:var(--acc);
  font-weight:650;font-size:.8rem;display:flex;align-items:center;justify-content:center}
.steps li::after{content:"";position:absolute;left:12.5px;top:26px;bottom:2px;width:1px;background:var(--line-soft)}
.steps li:last-child::after{display:none}
.card.warnb{border-color:rgba(251,191,36,.45);background:linear-gradient(var(--warn-dim),var(--warn-dim)),var(--panel)}
.lockwrap{max-width:430px;margin:9vh auto 0;text-align:center}
.lockwrap .fico{margin:0 auto 14px;width:44px;height:44px}
.lockwrap .fico svg{width:22px;height:22px}
.statrow{display:flex;gap:12px;flex-wrap:wrap;margin:4px 0 14px}
.statrow .stat{min-width:150px}
a.stat{display:block;text-decoration:none;color:var(--tx)}
a.stat b{color:var(--tx)}
a.stat.hot b{color:var(--acc)}
a.stat:hover{border-color:var(--tx3);color:var(--tx)}
`
